1	/**
2	 * Per-tool grammar — spec §16.4 / §16.5.
3	 *
4	 * Each tool's interaction model is captured here as plain data so the
5	 * tool can be unit-tested without DOM. The shape is consistent across
6	 * tools so the canvas can switch on `kind` and dispatch input.
7	 */
8	
9	export type ToolGrammarKind =
10	  | 'wall'
11	  | 'door'
12	  | 'window'
13	  | 'floor'
14	  | 'roof'
15	  | 'stair'
16	  | 'railing'
17	  | 'room'
18	  | 'dimension'
19	  | 'section'
20	  | 'tag';
21	
22	export type WallLocationLine =
23	  | 'wall-centerline'
24	  | 'finish-face-exterior'
25	  | 'finish-face-interior'
26	  | 'core-centerline'
27	  | 'core-face-exterior'
28	  | 'core-face-interior';
29	
30	export const WALL_LOCATION_LINE_ORDER: WallLocationLine[] = [
31	  'wall-centerline',
32	  'finish-face-exterior',
33	  'finish-face-interior',
34	  'core-centerline',
35	  'core-face-exterior',
36	  'core-face-interior',
37	];
38	
39	/** Cycle through the §16.4.1 location-line set on `Tab`. */
40	export function cycleWallLocationLine(current: WallLocationLine): WallLocationLine {
41	  const idx = WALL_LOCATION_LINE_ORDER.indexOf(current);
42	  if (idx < 0) return WALL_LOCATION_LINE_ORDER[0]!;
43	  return WALL_LOCATION_LINE_ORDER[(idx + 1) % WALL_LOCATION_LINE_ORDER.length]!;
44	}
45	
46	/** Wall tool state machine — minimum necessary to drive a chain mode
47	 * without leaking pointer details into the controller. */
48	export interface WallChainState {
49	  active: boolean;
50	  startMm: { xMm: number; yMm: number } | null;
51	  /** Locked endpoint after a click; chain mode begins from here. */
52	  chainAnchorMm: { xMm: number; yMm: number } | null;
53	  locationLine: WallLocationLine;
54	}
55	
56	export function initialWallChainState(): WallChainState {
57	  return {
58	    active: false,
59	    startMm: null,
60	    chainAnchorMm: null,
61	    locationLine: 'wall-centerline',
62	  };
63	}
64	
65	export type WallChainEvent =
66	  | { kind: 'tool-activated' }
67	  | { kind: 'tool-deactivated' }
68	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
69	  | { kind: 'cancel' }
70	  | { kind: 'tab-cycle-location' }
71	  | { kind: 'enter-finish' };
72	
73	export interface WallChainEffect {
74	  /** Wall span to commit, when a 2nd click closes a segment. */
75	  commitSegment?: {
76	    startMm: { xMm: number; yMm: number };
77	    endMm: { xMm: number; yMm: number };
78	    locationLine: WallLocationLine;
79	  };
80	  /** True when the tool stays active after the event. */
81	  stillActive: boolean;
82	  /** True when this event broke the chain (Esc). */
83	  chainBroken?: boolean;
84	}
85	
86	export function reduceWallChain(
87	  state: WallChainState,
88	  event: WallChainEvent,
89	): { state: WallChainState; effect: WallChainEffect } {
90	  if (event.kind === 'tool-activated') {
91	    return {
92	      state: { ...state, active: true, startMm: null, chainAnchorMm: null },
93	      effect: { stillActive: true },
94	    };
95	  }
96	  if (event.kind === 'tool-deactivated') {
97	    return {
98	      state: { ...initialWallChainState() },
99	      effect: { stillActive: false },
100	    };
101	  }
102	  if (!state.active) {
103	    return { state, effect: { stillActive: false } };
104	  }
105	  if (event.kind === 'tab-cycle-location') {
106	    return {
107	      state: { ...state, locationLine: cycleWallLocationLine(state.locationLine) },
108	      effect: { stillActive: true },
109	    };
110	  }
111	  if (event.kind === 'cancel') {
112	    return {
113	      state: { ...state, startMm: null, chainAnchorMm: null },
114	      effect: { stillActive: true, chainBroken: true },
115	    };
116	  }
117	  if (event.kind === 'enter-finish') {
118	    return {
119	      state: { ...initialWallChainState() },
120	      effect: { stillActive: false },
121	    };
122	  }
123	  // click
124	  const start = state.chainAnchorMm ?? state.startMm;
125	  if (!start) {
126	    return {
127	      state: { ...state, startMm: event.pointMm, chainAnchorMm: null },
128	      effect: { stillActive: true },
129	    };
130	  }
131	  const segment = {
132	    startMm: start,
133	    endMm: event.pointMm,
134	    locationLine: state.locationLine,
135	  };
136	  return {
137	    state: { ...state, startMm: null, chainAnchorMm: event.pointMm },
138	    effect: { commitSegment: segment, stillActive: true },
139	  };
140	}
141	
142	/* ────────────────────────────────────────────────────────────────────── */
143	/* Door / Window — §16.4.2 / §16.4.3                                       */
144	/* ────────────────────────────────────────────────────────────────────── */
145	
146	export interface HostedOpeningDefaults {
147	  widthMm: number;
148	  heightMm: number;
149	  sillHeightMm?: number;
150	}
151	
152	export type DoorSwing = 'left' | 'right';
153	export type DoorHand = 'in' | 'out';
154	
155	export interface DoorPlacement {
156	  wallId: string;
157	  alongT: number;
158	  widthMm: number;
159	  heightMm: number;
160	  swing: DoorSwing;
161	  hand: DoorHand;
162	}
163	
164	export const DOOR_DEFAULTS: HostedOpeningDefaults & {
165	  swing: DoorSwing;
166	  hand: DoorHand;
167	} = {
168	  widthMm: 900,
169	  heightMm: 2100,
170	  swing: 'left',
171	  hand: 'in',
172	};
173	
174	/** Spacebar flips swing side; Tab flips hand. */
175	export function flipDoorSwing(swing: DoorSwing): DoorSwing {
176	  return swing === 'left' ? 'right' : 'left';
177	}
178	
179	export function flipDoorHand(hand: DoorHand): DoorHand {
180	  return hand === 'in' ? 'out' : 'in';
181	}
182	
183	export const WINDOW_DEFAULTS: HostedOpeningDefaults = {
184	  widthMm: 1200,
185	  heightMm: 1500,
186	  sillHeightMm: 900,
187	};
188	
189	/* ────────────────────────────────────────────────────────────────────── */
190	/* Floor — §16.4.4                                                          */
191	/* ────────────────────────────────────────────────────────────────────── */
192	
193	export type FloorMode = 'pick-walls' | 'sketch';
194	
195	export interface FloorState {
196	  mode: FloorMode;
197	  sketchPolygonMm: { xMm: number; yMm: number }[];
198	  pickedWallIds: string[];
199	  thicknessMm: number;
200	}
201	
202	export function initialFloorState(): FloorState {
203	  return {
204	    mode: 'pick-walls',
205	    sketchPolygonMm: [],
206	    pickedWallIds: [],
207	    thicknessMm: 220,
208	  };
209	}
210	
211	export function toggleFloorMode(mode: FloorMode): FloorMode {
212	  return mode === 'pick-walls' ? 'sketch' : 'pick-walls';
213	}
214	
215	/* ────────────────────────────────────────────────────────────────────── */
216	/* Roof — §16.4.5                                                           */
217	/* ────────────────────────────────────────────────────────────────────── */
218	
219	export type RoofType = 'gable' | 'hip' | 'flat' | 'shed';
220	
221	export interface RoofState {
222	  type: RoofType;
223	  slopeDeg: number;
224	  /** Per-edge slope override; key is edge index. */
225	  edgeSlopes: Record<number, boolean>;
226	  eaveOverhangMm: number;
227	}
228	
229	export function initialRoofState(): RoofState {
230	  return {
231	    type: 'gable',
232	    slopeDeg: 35,
233	    edgeSlopes: {},
234	    eaveOverhangMm: 600,
235	  };
236	}
237	
238	export function toggleEdgeSlope(state: RoofState, edgeIdx: number): RoofState {
239	  const next = { ...state.edgeSlopes };
240	  next[edgeIdx] = !state.edgeSlopes[edgeIdx];
241	  return { ...state, edgeSlopes: next };
242	}
243	
244	/* ────────────────────────────────────────────────────────────────────── */
245	/* Stair — §16.4.6                                                          */
246	/* ────────────────────────────────────────────────────────────────────── */
247	
248	export type StairType = 'straight' | 'l-shape' | 'u-shape' | 'spiral';
249	
250	export interface StairCalcInput {
251	  baseLevelElevMm: number;
252	  topLevelElevMm: number;
253	  preferredRiserMm?: number;
254	  preferredTreadMm?: number;
255	}
256	
257	export interface StairCalcOutput {
258	  riserMm: number;
259	  treadMm: number;
260	  riserCount: number;
261	  treadCount: number;
262	  totalRiseMm: number;
263	}
264	
265	export const STAIR_RISER_MM_DEFAULT = 175;
266	export const STAIR_TREAD_MM_DEFAULT = 280;
267	
268	/** Auto-compute risers/treads for a straight run between two levels. */
269	export function computeStairRun(input: StairCalcInput): StairCalcOutput {
270	  const totalRise = input.topLevelElevMm - input.baseLevelElevMm;
271	  if (totalRise <= 0) {
272	    return {
273	      riserMm: STAIR_RISER_MM_DEFAULT,
274	      treadMm: STAIR_TREAD_MM_DEFAULT,
275	      riserCount: 0,
276	      treadCount: 0,
277	      totalRiseMm: 0,
278	    };
279	  }
280	  const desired = input.preferredRiserMm ?? STAIR_RISER_MM_DEFAULT;
281	  const riserCount = Math.max(2, Math.round(totalRise / desired));
282	  const riserMm = totalRise / riserCount;
283	  const treadMm = input.preferredTreadMm ?? STAIR_TREAD_MM_DEFAULT;
284	  return {
285	    riserMm,
286	    treadMm,
287	    riserCount,
288	    treadCount: riserCount - 1,
289	    totalRiseMm: totalRise,
290	  };
291	}
292	
293	/* ────────────────────────────────────────────────────────────────────── */
294	/* Railing — §16.4.7                                                        */
295	/* ────────────────────────────────────────────────────────────────────── */
296	
297	export type RailingHostKind = 'stair' | 'slab-edge' | 'sketch-path';
298	
299	export interface RailingDefaults {
300	  style: 'horizontal-bars-5x30';
301	  totalHeightMm: number;
302	  baluster: {
303	    spacingMm: number;
304	    diameterMm: number;
305	  };
306	}
307	
308	export const RAILING_DEFAULTS: RailingDefaults = {
309	  style: 'horizontal-bars-5x30',
310	  totalHeightMm: 1100,
311	  baluster: { spacingMm: 100, diameterMm: 30 },
312	};
313	
314	/* ────────────────────────────────────────────────────────────────────── */
315	/* Room marker — §16.4.8                                                    */
316	/* ────────────────────────────────────────────────────────────────────── */
317	
318	export interface RoomMarkerInput {
319	  /** Closed boundary forming the room — typically the auto-detected
320	   * polygon under the cursor. */
321	  outlineMm: { xMm: number; yMm: number }[];
322	}
323	
324	export function centroidMm(outline: { xMm: number; yMm: number }[]): { xMm: number; yMm: number } {
325	  if (outline.length === 0) return { xMm: 0, yMm: 0 };
326	  let area = 0;
327	  let cx = 0;
328	  let cy = 0;
329	  for (let i = 0; i < outline.length; i++) {
330	    const a = outline[i]!;
331	    const b = outline[(i + 1) % outline.length]!;
332	    const cross = a.xMm * b.yMm - b.xMm * a.yMm;
333	    area += cross;
334	    cx += (a.xMm + b.xMm) * cross;
335	    cy += (a.yMm + b.yMm) * cross;
336	  }
337	  if (area === 0) {
338	    const sum = outline.reduce((acc, p) => ({ xMm: acc.xMm + p.xMm, yMm: acc.yMm + p.yMm }), {
339	      xMm: 0,
340	      yMm: 0,
341	    });
342	    return { xMm: sum.xMm / outline.length, yMm: sum.yMm / outline.length };
343	  }
344	  area /= 2;
345	  return { xMm: cx / (6 * area), yMm: cy / (6 * area) };
346	}
347	
348	/* ────────────────────────────────────────────────────────────────────── */
349	/* Dimension — §16.4.9                                                      */
350	/* ────────────────────────────────────────────────────────────────────── */
351	
352	export type DimensionKind = 'linear' | 'aligned' | 'angular' | 'radial' | 'diameter';
353	
354	export const DIMENSION_HOTKEYS: Record<DimensionKind, string> = {
355	  linear: 'L',
356	  aligned: 'A',
357	  angular: 'G',
358	  radial: 'Q',
359	  diameter: 'Shift+Q',
360	};
361	
362	export interface DimensionState {
363	  kind: DimensionKind;
364	  firstWitnessMm: { xMm: number; yMm: number } | null;
365	  secondWitnessMm: { xMm: number; yMm: number } | null;
366	}
367	
368	export function initialDimensionState(): DimensionState {
369	  return { kind: 'linear', firstWitnessMm: null, secondWitnessMm: null };
370	}
371	
372	export function setDimensionKind(state: DimensionState, kind: DimensionKind): DimensionState {
373	  return { ...state, kind };
374	}
375	
376	/* ────────────────────────────────────────────────────────────────────── */
377	/* Section — §16.4.10                                                       */
378	/* ────────────────────────────────────────────────────────────────────── */
379	
380	export interface SectionDraftState {
381	  startMm: { xMm: number; yMm: number } | null;
382	  endMm: { xMm: number; yMm: number } | null;
383	  /** +1 means depth axis is to the right of the line direction. */
384	  depthSign: 1 | -1;
385	}
386	
387	export function initialSectionDraft(): SectionDraftState {
388	  return { startMm: null, endMm: null, depthSign: 1 };
389	}
390	
391	export function flipSectionDepth(state: SectionDraftState): SectionDraftState {
392	  return { ...state, depthSign: state.depthSign === 1 ? -1 : 1 };
393	}
394	
395	/* ────────────────────────────────────────────────────────────────────── */
396	/* Tag subdropdown — §16.5                                                  */
397	/* ────────────────────────────────────────────────────────────────────── */
398	
399	export type TagFamily = 'tag-door' | 'tag-window' | 'tag-wall' | 'tag-room' | 'tag-by-category';
400	
401	export const TAG_FAMILIES: { id: TagFamily; label: string }[] = [
402	  { id: 'tag-door', label: 'Tag Door' },
403	  { id: 'tag-window', label: 'Tag Window' },
404	  { id: 'tag-wall', label: 'Tag Wall' },
405	  { id: 'tag-room', label: 'Tag Room' },
406	  { id: 'tag-by-category', label: 'Tag by Category' },
407	];
408

