750	          bumpGeom((x) => x + 1);
751	          return;
752	        }
753	        const ox = Math.min(dr.sx, sp.xMm);
754	        const oy = Math.min(dr.sy, sp.yMm);
755	        const widthMm = Math.abs(sp.xMm - dr.sx);
756	        const depthMm = Math.abs(sp.yMm - dr.sy);
757	        if (widthMm < 200 || depthMm < 200) {
758	          draftRef.current = undefined;
759	          bumpGeom((x) => x + 1);
760	          return;
761	        }
762	        onSemanticCommand({
763	          type: 'createRoomRectangle',
764	          levelId: lvlId,
765	          origin: { xMm: ox, yMm: oy },
766	          widthMm,
767	          depthMm,
768	        });
769	        draftRef.current = undefined;
770	        bumpGeom((x) => x + 1);
